        <div class="chart-bar" style="height:${pct}%"></div>
        <div class="chart-bar-label">${label}</div>
      </div>`;
  }).join('');

  return `
    <div class="chart-section">
      <h4>일별 클릭 (최근 30일)</h4>
      <div class="chart-bars">${bars}</div>
    </div>`;
}

