import Database from 'better-sqlite3';
import { fileURLToPath } from 'url';
import { dirname, join } from 'path';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DB_PATH = join(__dirname, 'data', 'urls.db');

// Ensure data directory exists
import { mkdirSync } from 'fs';
mkdirSync(join(__dirname, 'data'), { recursive: true });

const db = new Database(DB_PATH);

// Enable WAL mode for better concurrent read performance
db.pragma('journal_mode = WAL');
db.pragma('foreign_keys = ON');

// Schema initialization
db.exec(`
  CREATE TABLE IF NOT EXISTS urls (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    code        TEXT    UNIQUE NOT NULL,
    original_url TEXT   NOT NULL,
    is_custom   INTEGER DEFAULT 0,
    click_count INTEGER DEFAULT 0,
    created_at  TEXT    DEFAULT (datetime('now')),
    expires_at  TEXT,
    last_clicked_at TEXT
  );

  CREATE INDEX IF NOT EXISTS idx_urls_code ON urls(code);
  CREATE INDEX IF NOT EXISTS idx_urls_expires ON urls(expires_at) WHERE expires_at IS NOT NULL;

  CREATE TABLE IF NOT EXISTS click_logs (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    url_id      INTEGER NOT NULL,
    clicked_at  TEXT    DEFAULT (datetime('now')),
    ip_address  TEXT,
    user_agent  TEXT,
    referer     TEXT,
    FOREIGN KEY (url_id) REFERENCES urls(id) ON DELETE CASCADE
  );

  CREATE INDEX IF NOT EXISTS idx_clicks_url_id ON click_logs(url_id);
  CREATE INDEX IF NOT EXISTS idx_clicks_at ON click_logs(clicked_at);
`);

// Prepared statements for performance
export const stmts = {
  findByCode: db.prepare(`
    SELECT * FROM urls
    WHERE code = ?
      AND (expires_at IS NULL OR expires_at > datetime('now'))
  `),

  findByCodeAny: db.prepare(`SELECT * FROM urls WHERE code = ?`),

  create: db.prepare(`
    INSERT INTO urls (code, original_url, is_custom, expires_at)
    VALUES (@code, @original_url, @is_custom, @expires_at)
  `),

  incrementClick: db.prepare(`
    UPDATE urls
    SET click_count = click_count + 1,
        last_clicked_at = datetime('now')
    WHERE code = ?
  `),

  logClick: db.prepare(`
    INSERT INTO click_logs (url_id, ip_address, user_agent, referer)
    VALUES (@url_id, @ip_address, @user_agent, @referer)
  `),

  listAll: db.prepare(`
    SELECT id, code, original_url, is_custom, click_count,
           created_at, expires_at, last_clicked_at,
           CASE
             WHEN expires_at IS NULL THEN 'active'
             WHEN expires_at <= datetime('now') THEN 'expired'
             ELSE 'active'
           END AS status
    FROM urls
    ORDER BY created_at DESC
    LIMIT 100
  `),

  deleteByCode: db.prepare(`DELETE FROM urls WHERE code = ?`),

  getClickLogs: db.prepare(`
    SELECT clicked_at, ip_address, user_agent, referer
    FROM click_logs
    WHERE url_id = ?
    ORDER BY clicked_at DESC
    LIMIT 50
  `),

  getClicksByDay: db.prepare(`
    SELECT date(clicked_at) AS day, COUNT(*) AS count
    FROM click_logs
    WHERE url_id = ?
      AND clicked_at >= datetime('now', '-30 days')
    GROUP BY day
    ORDER BY day ASC
  `),
};

// Transactional click recording
export const recordClick = db.transaction((code, meta) => {
  stmts.incrementClick.run(code);
  const url = stmts.findByCodeAny.get(code);
  if (url) {
    stmts.logClick.run({
      url_id: url.id,
      ip_address: meta.ip,
      user_agent: meta.userAgent,
      referer: meta.referer,
    });
  }
});

export default db;

import { Router } from 'express';
import { nanoid } from 'nanoid';
import { stmts } from '../database.js';

const router = Router();

// Validate URL format
function isValidUrl(str) {
  try {
    const url = new URL(str);
    return url.protocol === 'http:' || url.protocol === 'https:';
  } catch {
    return false;
  }
}

// POST /api/shorten
router.post('/shorten', (req, res) => {
  const { url, custom_code, expires_in_days } = req.body;

  if (!url || typeof url !== 'string') {
    return res.status(400).json({ error: 'url is required' });
  }

  const trimmedUrl = url.trim();
  if (!isValidUrl(trimmedUrl)) {
    return res.status(400).json({ error: 'Invalid URL. Must start with http:// or https://' });
  }

  // Determine short code
  let code;
  let isCustom = false;

  if (custom_code) {
    const sanitized = custom_code.trim().replace(/[^a-zA-Z0-9_-]/g, '');
    if (!sanitized || sanitized.length < 2 || sanitized.length > 50) {
      return res.status(400).json({ error: 'Custom code must be 2-50 alphanumeric characters' });
    }
    const existing = stmts.findByCodeAny.get(sanitized);
    if (existing) {
      return res.status(409).json({ error: `Custom code "${sanitized}" is already taken` });
    }
    code = sanitized;
    isCustom = true;
  } else {
    // Generate unique code (retry on collision, extremely rare)
    let attempts = 0;
    do {
      code = nanoid(7);
      attempts++;
      if (attempts > 10) {
        return res.status(500).json({ error: 'Failed to generate unique code' });
      }
    } while (stmts.findByCodeAny.get(code));
  }

  // Calculate expiration
  let expiresAt = null;
  if (expires_in_days) {
    const days = parseInt(expires_in_days, 10);
    if (isNaN(days) || days < 1 || days > 3650) {
      return res.status(400).json({ error: 'expires_in_days must be between 1 and 3650' });
    }
    const exp = new Date();
    exp.setDate(exp.getDate() + days);
    expiresAt = exp.toISOString().replace('T', ' ').slice(0, 19);
  }

  try {
    stmts.create.run({
      code,
      original_url: trimmedUrl,
      is_custom: isCustom ? 1 : 0,
      expires_at: expiresAt,
    });
  } catch (err) {
    if (err.message.includes('UNIQUE constraint')) {
      return res.status(409).json({ error: 'Code already exists' });
    }
    throw err;
  }

  const baseUrl = `${req.protocol}://${req.get('host')}`;
  const shortUrl = `${baseUrl}/${code}`;

  return res.status(201).json({
    code,
    short_url: shortUrl,
    original_url: trimmedUrl,
    is_custom: isCustom,
    expires_at: expiresAt,
    created_at: new Date().toISOString(),
  });
});

// GET /api/urls — list all URLs
router.get('/urls', (_req, res) => {
  const urls = stmts.listAll.all();
  return res.json({ urls, total: urls.length });
});

// GET /api/urls/:code — detail + stats
router.get('/urls/:code', (req, res) => {
  const { code } = req.params;
  const url = stmts.findByCodeAny.get(code);
  if (!url) {
    return res.status(404).json({ error: 'URL not found' });
  }

  const clicksByDay = stmts.getClicksByDay.all(url.id);
  const recentClicks = stmts.getClickLogs.all(url.id);

  return res.json({
    ...url,
    status: url.expires_at && new Date(url.expires_at) <= new Date() ? 'expired' : 'active',
    clicks_by_day: clicksByDay,
    recent_clicks: recentClicks,
  });
});

// DELETE /api/urls/:code
router.delete('/urls/:code', (req, res) => {
  const { code } = req.params;
  const url = stmts.findByCodeAny.get(code);
  if (!url) {
    return res.status(404).json({ error: 'URL not found' });
  }
  stmts.deleteByCode.run(code);
  return res.json({ message: `"${code}" deleted successfully` });
});

export default router;

import { Router } from 'express';
import { stmts, recordClick } from '../database.js';

const router = Router();

// GET /:code — redirect to original URL
router.get('/:code', (req, res) => {
  const { code } = req.params;

  // Basic sanity check — avoid interfering with static assets
  if (code.includes('.') || code.length > 50) {
    return res.status(404).send('Not found');
  }

  const url = stmts.findByCode.get(code);

  if (!url) {
    // Check if it exists but is expired
    const expired = stmts.findByCodeAny.get(code);
    if (expired) {
      return res.status(410).send(`
        <html><body style="font-family:sans-serif;text-align:center;padding:60px">
          <h2>🔗 Link Expired</h2>
          <p>This short link has expired.</p>
          <a href="/">← Go to homepage</a>
        </body></html>
      `);
    }
    return res.status(404).send(`
      <html><body style="font-family:sans-serif;text-align:center;padding:60px">
        <h2>🔍 Link Not Found</h2>
        <p>This short link does not exist.</p>
        <a href="/">← Go to homepage</a>
      </body></html>
    `);
  }

  // Record the click asynchronously (non-blocking via sync tx but fast)
  try {
    recordClick(code, {
      ip: req.ip,
      userAgent: req.get('user-agent') || '',
      referer: req.get('referer') || '',
    });
  } catch (err) {
    // Never fail a redirect due to analytics error
    console.error('[click tracking error]', err.message);
  }

  // 302 (temporary) redirect — allows analytics to work correctly
  // Use 301 only if you want to cache at browser level (kills click tracking)
  return res.redirect(302, url.original_url);
});

export default router;

import express from 'express';
import { fileURLToPath } from 'url';
import { dirname, join } from 'path';

import apiRouter from './routes/api.js';
import redirectRouter from './routes/redirect.js';

const __dirname = dirname(fileURLToPath(import.meta.url));

const app = express();

// ── Middleware ──────────────────────────────────────────────
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Trust proxy for accurate IP logging (behind nginx/load balancer)
app.set('trust proxy', 1);

// Static files (UI)
app.use(express.static(join(__dirname, 'public')));

// ── Routes ─────────────────────────────────────────────────
app.use('/api', apiRouter);

// Health check endpoint (for load balancers / monitoring)
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Redirect route — must come LAST (catch-all for /:code)
app.use(redirectRouter);

// ── Global error handler ───────────────────────────────────
app.use((err, _req, res, _next) => {
  console.error('[unhandled error]', err);
  res.status(500).json({ error: 'Internal server error' });
});

// ── Start ──────────────────────────────────────────────────
const PORT = process.env.PORT;
if (!PORT) {
  console.error('❌  PORT environment variable is required. Example: PORT=3000 node server.js');
  process.exit(1);
}

app.listen(PORT, () => {
  console.log(`✅  URL Shortener running on http://localhost:${PORT}`);
  console.log(`   Health: http://localhost:${PORT}/health`);
  console.log(`   API:    http://localhost:${PORT}/api`);
});

export default app;

